// Check if AI Analysis succeeded or failed
const aiResult = $input.first().json;
const context = $('Build AI Context').first().json;

// Detect failure: continueOnFail returns error info
const hasError = aiResult.error || !aiResult.choices || aiResult.choices.length === 0;

if (hasError) {
  // AI failed - return canned response
  return {
    ...context,
    aiFailed: true,
    aiResponse: 'Thank you for your message. I am experiencing a temporary issue. A team member will get back to you shortly.',
    intent: 'error_fallback',
    action: 'respond',
    airtableOperation: { needed: false },
    confidence: 0,
  };
}

// AI succeeded - pass through to Parse AI Decision
return aiResult;

// Check if current time is within agent's working hours
const message = $input.first().json;
const agent = message.agent;

// If no working hours configured, always on
if (!agent.workingHours || !agent.workingDays) {
  return { ...message, withinWorkingHours: true };
}

const tz = agent.timezone || 'Africa/Johannesburg';
const now = new Date();

// Get current time in agent's timezone
const timeStr = now.toLocaleTimeString('en-GB', { timeZone: tz, hour12: false });
const dayOfWeek = now.toLocaleDateString('en-US', { timeZone: tz, weekday: 'short' });
const dayMap = { 'Mon': 1, 'Tue': 2, 'Wed': 3, 'Thu': 4, 'Fri': 5, 'Sat': 6, 'Sun': 0 };
const currentDay = dayMap[dayOfWeek] || 0;

// Check working days (CSV like '1,2,3,4,5')
const workingDays = agent.workingDays.split(',').map(d => parseInt(d.trim()));
if (!workingDays.includes(currentDay)) {
  return { ...message, withinWorkingHours: false };
}

// Check working hours (format: '08:00-17:00')
const [startStr, endStr] = agent.workingHours.split('-').map(s => s.trim());
const currentMinutes = parseInt(timeStr.split(':')[0]) * 60 + parseInt(timeStr.split(':')[1]);
const startMinutes = parseInt(startStr.split(':')[0]) * 60 + parseInt(startStr.split(':')[1]);
const endMinutes = parseInt(endStr.split(':')[0]) * 60 + parseInt(endStr.split(':')[1]);

const withinHours = currentMinutes >= startMinutes && currentMinutes < endMinutes;

return { ...message, withinWorkingHours: withinHours };

